const { access_token, refresh_token } = $input.first().json;
if (!access_token) throw new Error('Token refresh failed — no access_token in response');

// Log success. In production, update your credential store or env vars.
// For n8n Cloud: update the ML_ACCESS_TOKEN environment variable via n8n API
// or store tokens in a dedicated Google Sheets cell.
console.log('ML token refreshed at', new Date().toISOString());

return [{ json: { access_token, refresh_token, refreshedAt: new Date().toISOString() } }];
